protected void initCustVendTrans(
    CustVendTrans _custVendTrans,
    LedgerVoucher _ledgerPostingJournal,
    boolean _useSubLedger)
{
    // 1. Let the standard code initialize the core CustTrans fields
    next initCustVendTrans(_custVendTrans, _ledgerPostingJournal, _useSubLedger);

    // 2. Safely cast the Map and protected variables to Table Buffers
    if (_custVendTrans.TableId == tableNum(CustTrans))
    {
        // Map assignment automatically keeps the by-reference pointer
        CustTrans       localCustTrans       = _custVendTrans;
        CustInvoiceJour localCustInvoiceJour = this.custVendInvoiceJour;

        // 3. Flow the DocumentNum
        if (localCustInvoiceJour && localCustInvoiceJour.DocumentNum)
        {
            localCustTrans.DocumentNum = localCustInvoiceJour.DocumentNum;
        }
    }
}
